lt now. Working around this change is pretty straightforward, just call `jl_gc_mark_queue_obj` for all non-null pointers, but I think null-pointers in this array should remain supported.~~

When an old foreign object contains an array of pointers where at least one points to a young object, `jl_gc_mark_queue_objarray` does not fully update the GC state of the parent object. Previously it was possible to return 0 from the mark function when `jl_gc_mark_queue_objarray` was used.

Reproducer:

```
#include <julia.h>
#include <julia_gcext.h>

JULIA_DEFINE_FAST_TLS

    typedef struct
{
    jl_value_t **ptrs;
} mytype;

uintptr_t markfunc(jl_ptls_t ptls, jl_value_t *obj)
{
    jl_gc_mark_queue_objarray(ptls, obj, ((mytype *)obj)->ptrs, 1);
    return 0;
}

void sweepfunc(jl_value_t *obj)
{
    mytype *myinstance = (mytype *)obj;
    free(myinstance->ptrs);
}

mytype *new_mytype(jl_datatype_t *ty)
{
    jl_ptls_t ptls = jl_current_task->ptls;
    mytype *instance = (mytype *)jl_gc_alloc_typed(ptls, sizeof(mytype), (void *)ty);
    instance->ptrs = malloc(sizeof(jl_value_t *));
    instance->ptrs[0] = NULL;
    jl_gc_schedule_foreign_sweepfunc(ptls, (jl_value_t *)instance);

    return instance;
}

int main(int argc, char *argv[])
{
    jl_init();
    jl_sym_t *sym = jl_symbol("ForeignType");
    jl_datatype_t *ty = jl_new_foreign_type(
        sym, jl_base_module, jl_any_type, markfunc, sweepfunc, 1, 0);

    jl_set_const(jl_base_module, sym, (jl_value_t *)ty);

    jl_value_t **args;
    JL_GC_PUSHARGS(args, 1);

    mytype *instance = new_mytype(ty);
    args[0] = (jl_value_t *)instance;
    jl_gc_collect(JL_GC_FULL);
    jl_gc_collect(JL_GC_FULL);
    assert(jl_astaggedvalue(instance)->bits.gc == 3);

    instance->ptrs[0] = (jl_value_t *)new_mytype(ty);
    jl_gc_wb((const void *)instance, (const void *)instance->ptrs[0]);
    assert(jl_astaggedvalue(instance)->bits.gc == 1);
    jl_gc_collect(JL_GC_FULL);
    // The GC-bits are 3 when I use the most recent master, 1 when I use Julia 1.8 or 1.9
    // If the GC bits are 3, a GC error occurs
    assert(jl_astaggedvalue(instance)->bits.gc == 1); 
    jl_gc_collect(JL_GC_FULL);

    JL_GC_POP();

    jl_atexit_hook(0);
    return 0;
}
