#include <pthread.h>

JULIA_DEFINE_FAST_TLS

void *thread(void *ptr)
{
    int i = 1000;
    jl_adopt_thread();
    jl_eval_string("println(\"Foreign thread\")");

    while (--i) {
        jl_eval_string("sleep(0.01)");
    }

    return NULL;
}

int main(int argc, char *argv[])
{
    jl_init();

    pthread_t thr;
    pthread_create(&thr, NULL, *thread, NULL);

    jl_eval_string("sleep(1)");
    jl_eval_string("println(\"Collect\")");
    jl_gc_collect(JL_GC_FULL);
    jl_eval_string("println(\"Done\")");

    pthread_join(thr, NULL);

    jl_atexit_hook(0);
    return 0;
}
